async function loadMetadata() {
	// Metadata is already available if embedded, or we can load it
	// If not embedded, this will try to fetch from source
	if (CONDITIONS_METADATA.length === 0) {
		try {
			const module =
				await import("../../src/lib/server/conditions-metadata.js")
			CONDITIONS_METADATA = module.CONDITIONS_METADATA || []
			PIONEERS_METADATA = module.PIONEERS_METADATA || []
			console.log(
				`✓ Loaded metadata from src/lib/server: ${CONDITIONS_METADATA.length} conditions`,
			)
		} catch (importError) {
			console.error("Failed to import metadata:", importError.message)
			console.log("No metadata available for condition matching")
		}
	}

	// Build the CONDITIONS array after loading metadata
	buildConditionsArray()
}

